import 'dart:html' as html;

class WebForegroundSound {
  static const Duration _minPlayGap = Duration(milliseconds: 1200);
  static DateTime? _lastPlayedAt;
  static String? _activeConversationId;

  static final html.AudioElement _messageTone = html.AudioElement(
      'data:audio/wav;base64,')
    ..preload = 'auto';

  static void setActiveConversationId(String? conversationId) {
    _activeConversationId = conversationId;
  }

  static Future<void> playIncomingMessageTone({
    required String conversationId,
  }) async {
    if (_activeConversationId == conversationId) return;
    final now = DateTime.now();
    final lastPlayedAt = _lastPlayedAt;
    if (lastPlayedAt != null && now.difference(lastPlayedAt) < _minPlayGap) {
      return;
    }
    _lastPlayedAt = now;
    try {
      _messageTone.pause();
      _messageTone.currentTime = 0;
      await _messageTone.play();
    } catch (_) {
      // Safari/Web autoplay policy may block sound until user interacts.
    }
  }
}
